package main

import (
	"encoding/json"
	"fmt"
)

type Book struct {
	Title      string
	Author     string
	InternalID string
}

func (b Book) MarshalJSON() ([]byte, error) {
	type Alias struct {
		Title      string `json:"title"`
		Author     string `json:"author"`
		InternalID string `json:"internal_id"`
	}
	return json.Marshal(Alias{
		Title:      b.Title,
		Author:     b.Author,
		InternalID: "***", // TODO: change to "[redacted]"
	})
}

func main() {
	b := Book{Title: "Ender's Game", Author: "Orson Scott Card", InternalID: "LIB-0032-1985"}
	data, _ := json.Marshal(b)
	fmt.Println(string(data))
}

